package ir.tahamohamadi.publication; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.LocalDate;
@Entity @Table(name="publication") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class Publication extends AuditedSoftDeletableEntity { @Column(name="publication_key",nullable=false) private String publicationKey; @Enumerated(EnumType.STRING) @Column(name="content_status",nullable=false) private ContentStatus contentStatus; @Enumerated(EnumType.STRING) @Column(name="publication_stage",nullable=false) private PublicationStage publicationStage; private String doi; @Column(name="external_url") private String externalUrl; @Column(name="published_on") private LocalDate publishedOn; private int year; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="cover_media_id") private MediaAsset coverMedia; @Column(name="sort_order") private int sortOrder; }
